// Validate and extract incoming patient data
const body = $input.first().json.body || $input.first().json;

const required = ['patient_name', 'patient_email', 'appointment_date', 'clinic_name'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

return [{
  json: {
    patient_name: body.patient_name.trim(),
    patient_first_name: body.patient_name.trim().split(' ')[0],
    patient_email: body.patient_email.trim().toLowerCase(),
    patient_phone: body.patient_phone || null,
    appointment_date: body.appointment_date,
    appointment_type: body.appointment_type || '',
    provider_name: (body.provider_name || body.dentist_name || '').trim(),
    appointment_notes: body.appointment_notes || '',
    clinic_name: body.clinic_name.trim(),
    clinic_review_url: body.clinic_review_url || body.clinic_google_review_url || 'https://g.page/r/YOUR_CLINIC_REVIEW_LINK',
    clinic_manager_email: body.clinic_manager_email || 'manager@clinic.com',
    gbp_account_name: body.gbp_account_name || 'accounts/YOUR_ACCOUNT_ID',
    gbp_location_name: body.gbp_location_name || 'locations/YOUR_LOCATION_ID',
    send_sms: body.patient_phone ? true : false,
    timestamp: new Date().toISOString()
  }
}];

// DEDUP & OPT-OUT CHECK
const patientData = $('Validate & Structure Data').first().json;

let sheetRow = null;
try {
  const lookupResult = $('Lookup Opt-Out Sheet').first().json;
  if (lookupResult && lookupResult.patient_email) {
    sheetRow = lookupResult;
  }
} catch (e) {}

if (sheetRow) {
  const opted_out = String(sheetRow.opted_out).toLowerCase() === 'true';
  if (opted_out) {
    throw new Error(`HALTED: Patient ${patientData.patient_email} has opted out of review requests.`);
  }
  if (sheetRow.last_request_date) {
    const daysSince = (Date.now() - new Date(sheetRow.last_request_date).getTime()) / (1000 * 60 * 60 * 24);
    if (daysSince < 90) {
      throw new Error(`HALTED: Patient ${patientData.patient_email} received a review request ${Math.floor(daysSince)} days ago (within 90-day window).`);
    }
  }
}

return [{ json: patientData }];

