const patientData = $('Validate & Structure Data').first().json;
const reviewUrl = patientData.clinic_review_url;

const rawSource =
  $input.first().json.content?.[0]?.text ||
  $input.first().json.text ||
  '';

const rawText = rawSource
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

if (!rawText) {
  return [{
    json: {
      email_subject: `Thanks for visiting ${patientData.patient_first_name}`,
      email_body: `<p>Hi ${patientData.patient_first_name},</p><p>Thank you for visiting ${patientData.clinic_name}.</p><p>If you have a moment, <a href="${reviewUrl}">leave us a review here</a>.</p><p>We appreciate your support.</p>`,
      sentiment_flag: 'positive',
      review_link: reviewUrl,
      fallback_used: true,
      fallback_reason: 'Claude returned no text output'
    }
  }];
}

let claudeOutput;
try {
  claudeOutput = JSON.parse(rawText);
} catch (error) {
  return [{
    json: {
      email_subject: `Thanks for visiting ${patientData.patient_first_name}`,
      email_body: `<p>Hi ${patientData.patient_first_name},</p><p>Thank you for visiting ${patientData.clinic_name}.</p><p>If you have a moment, <a href="${reviewUrl}">leave us a review here</a>.</p><p>We appreciate your support.</p>`,
      sentiment_flag: 'positive',
      review_link: reviewUrl,
      fallback_used: true,
      fallback_reason: `Claude JSON parse failed: ${error.message}`
    }
  }];
}

const finalBody = (claudeOutput.email_body || '').replace(
  '{{REVIEW_LINK}}',
  `<a href="${reviewUrl}">Leave a review here</a>`
);

return [{
  json: {
    email_subject: claudeOutput.email_subject || `Thanks for visiting ${patientData.patient_first_name}`,
    email_body: finalBody || `<p>Hi ${patientData.patient_first_name},</p><p>Thank you for visiting ${patientData.clinic_name}.</p><p>If you have a moment, <a href="${reviewUrl}">leave us a review here</a>.</p><p>We appreciate your support.</p>`,
    sentiment_flag: claudeOutput.sentiment_flag || 'positive',
    review_link: reviewUrl,
    fallback_used: false
  }
}];

const data = $('Validate & Structure Data').first().json;
console.log(JSON.stringify({
  event: 'review_request_sent',
  clinic: data.clinic_name,
  patient_email: data.patient_email,
  provider: data.provider_name,
  appointment_date: data.appointment_date,
  timestamp: new Date().toISOString()
}));
return $input.all();

